+export function traverseSerial<T, U, E>(
+  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
+  taskFn?: (item: T) => Task<U, E>
+): Task<U[], E> | ((items: Iterable<T>) => Task<U[], E>) {
+  return taskFn === undefined
+    ? (items) => traverseSerial(items, itemsOrFn as (item: T) => Task<U, E>)
+    : new Task((resolve, reject) => {
+        const values: U[] = [];
+        const iterator = (itemsOrFn as Iterable<T>)[Symbol.iterator]();
+        const next = (): void => {
+          const item = iterator.next();
+          if (item.done) return resolve(values);
+          taskFn(item.value).match({
