+/** Pair two tasks when both resolve. */
+export function zip<A, B, E, F>(a: Task<A, E>, b: Task<B, F>): Task<[A, B], E | F> {
+  return a.andThen((aValue) => b.map((bValue) => [aValue, bValue] as [A, B]));
+}
+
+/** Combine two tasks when both resolve. */
+export function zipWith<A, B, U, E, F>(
+  a: Task<A, E>, b: Task<B, F>, fn: (a: A, b: B) => U
+): Task<U, E | F> {
+  return zip(a, b).map(([aValue, bValue]) => fn(aValue, bValue));
